[
  {
    "type": "text",
    "text": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Vancouver Dinner Organizer — March 27, 2026</title>
<style>
  :root {
    --bg: #0d0f18;
    --surface: #13162a;
    --surface2: #1c2040;
    --surface3: #242850;
    --accent: #d4a847;
    --accent2: #5fa8c7;
    --accent3: #7ec98a;
    --red: #d96b6b;
    --purple: #9d80d4;
    --text: #ede9e1;
    --muted: #7a7892;
    --border: rgba(212,168,71,0.13);
    --border2: rgba(255,255,255,0.07);
    --radius: 10px;
    --radius-lg: 16px;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    padding-bottom: 80px;
  }

  /* NAV */
  nav {
    position: sticky;
    top: 0;
    z-index: 100;
    background: rgba(13,15,24,0.92);
    backdrop-filter: blur(16px);
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    gap: 0;
    padding: 0 28px;
    height: 54px;
  }
  .nav-brand {
    font-size: 0.82rem;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--accent);
    font-weight: 600;
    margin-right: 32px;
    white-space: nowrap;
  }
  .nav-tabs {
    display: flex;
    gap: 0;
    flex: 1;
    overflow-x: auto;
    scrollbar-width: none;
  }
  .nav-tabs::-webkit-scrollbar { display: none; }
  .tab-btn {
    background: none;
    border: none;
    color: var(--muted);
    font-size: 0.83rem;
    padding: 0 18px;
    height: 54px;
    cursor: pointer;
    border-bottom: 2px solid transparent;
    white-space: nowrap;
    transition: color 0.15s, border-color 0.15s;
    font-family: inherit;
  }
  .tab-btn:hover { color: var(--text); }
  .tab-btn.active { color: var(--accent); border-bottom-color: var(--accent); }

  /* HEADER */
  header {
    padding: 44px 36px 36px;
    border-bottom: 1px solid var(--border);
    background: linear-gradient(135deg, var(--surface) 0%, var(--bg) 100%);
    position: relative;
    overflow: hidden;
  }
  header::after {
    content: '';
    position: absolute;
    top: -60px; right: -60px;
    width: 320px; height: 320px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(212,168,71,0.06) 0%, transparent 70%);
    pointer-events: none;
  }
  .header-top {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    flex-wrap: wrap;
    gap: 20px;
  }
  .event-label {
    font-size: 0.7rem;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--accent);
    margin-bottom: 8px;
    font-weight: 600;
  }
  header h1 {
    font-size: 2rem;
    font-weight: 300;
    letter-spacing: -0.025em;
    color: var(--text);
    margin-bottom: 6px;
  }
  header .sub { color: var(--muted); font-size: 0.92rem; }
  .countdown-block {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 14px 22px;
    text-align: center;
    min-width: 140px;
  }
  #countdown-days {
    font-size: 2.4rem;
    font-weight: 700;
    color: var(--accent);
    line-height: 1;
    display: block;
  }
  .countdown-label { font-size: 0.72rem; letter-spacing: 0.12em; text-transform: uppercase; color: var(--muted); margin-top: 4px; }

  /* PROGRESS BAR */
  .progress-strip {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    gap: 1px;
    background: var(--border2);
    border-top: 1px solid var(--border2);
    margin-top: 0;
  }
  .prog-step {
    background: var(--surface);
    padding: 12px 18px;
    cursor: pointer;
    transition: background 0.15s;
    position: relative;
  }
  .prog-step:hover { background: var(--surface2); }
  .prog-step.done { background: rgba(126,201,138,0.07); }
  .prog-step.done .prog-label { color: var(--accent3); }
  .prog-step.active-step { background: rgba(212,168,71,0.06); }
  .prog-step.active-step .prog-label { color: var(--accent); }
  .prog-date { font-size: 0.68rem; letter-spacing: 0.1em; text-transform: uppercase; color: var(--muted); margin-bottom: 3px; }
  .prog-label { font-size: 0.82rem; color: var(--text); }
  .prog-check {
    display: inline-block;
    width: 14px; height: 14px;
    border: 1.5px solid var(--border2);
    border-radius: 3px;
    margin-right: 6px;
    vertical-align: middle;
    cursor: pointer;
    flex-shrink: 0;
    position: relative;
  }
  .prog-check.checked {
    background: var(--accent3);
    border-color: var(--accent3);
  }
  .prog-check.checked::after {
    content: '';
    position: absolute;
    left: 3px; top: 0px;
    width: 5px; height: 9px;
    border: 2px solid var(--bg);
    border-top: none;
    border-left: none;
    transform: rotate(45deg);
  }

  /* MAIN LAYOUT */
  .main { max-width: 1100px; margin: 0 auto; padding: 32px 24px 0; }
  .tab-panel { display: none; }
  .tab-panel.active { display: block; }
  section { margin-bottom: 48px; }
  .section-label {
    font-size: 0.68rem;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--accent);
    margin-bottom: 18px;
    padding-bottom: 8px;
    border-bottom: 1px solid var(--border);
  }

  /* STATUS CARDS */
  .status-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 16px; }
  .stat-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 18px 20px;
  }
  .stat-num {
    font-size: 2rem;
    font-weight: 700;
    color: var(--accent);
    line-height: 1;
    margin-bottom: 4px;
  }
  .stat-label { font-size: 0.8rem; color: var(--muted); }

  /* VENUE SELECTOR */
  .venue-cards { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 16px; margin-top: 4px; }
  .venue-card {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: var(--radius);
    padding: 18px 20px;
    cursor: pointer;
    transition: border-color 0.15s, background 0.15s;
    position: relative;
  }
  .venue-card:hover { border-color: rgba(212,168,71,0.35); background: var(--surface2); }
  .venue-card.selected { border-color: var(--accent); background: rgba(212,168,71,0.06); }
  .venue-card.selected::after {
    content: 'SELECTED';
    position: absolute;
    top: 12px; right: 12px;
    font-size: 0.6rem;
    letter-spacing: 0.12em;
    color: var(--accent);
    border: 1px solid var(--accent);
    padding: 2px 6px;
    border-radius: 3px;
  }
  .venue-name { font-size: 0.97rem; font-weight: 600; margin-bottom: 4px; }
  .venue-meta { font-size: 0.78rem; color: var(--muted); line-height: 1.5; }
  .venue-phone { font-size: 0.82rem; color: var(--accent2); margin-top: 6px; font-family: 'Courier New', monospace; }

  /* GUEST TABLE */
  .guest-table-wrap { overflow-x: auto; border: 1px solid var(--border); border-radius: var(--radius-lg); }
  table.guest-table { width: 100%; border-collapse: collapse; min-width: 700px; }
  .guest-table th {
    font-size: 0.67rem;
    letter-spacing: 0.13em;
    text-transform: uppercase;
    color: var(--muted);
    padding: 11px 16px;
    text-align: left;
    background: var(--surface2);
    border-bottom: 1px solid var(--border);
  }
  .guest-table td {
    padding: 10px 16px;
    border-bottom: 1px solid var(--border2);
    font-size: 0.87rem;
    vertical-align: middle;
  }
  .guest-table tr:last-child td { border-bottom: none; }
  .guest-table tr:hover td { background: rgba(255,255,255,0.02); }
  .guest-table input[type="text"],
  .guest-table input[type="tel"],
  .guest-table select {
    background: var(--surface2);
    border: 1px solid var(--border);
    color: var(--text);
    border-radius: 5px;
    padding: 5px 9px;
    font-size: 0.83rem;
    width: 100%;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
  }
  .guest-table input:focus,
  .guest-table select:focus { border-color: rgba(212,168,71,0.5); }
  .status-pill {
    display: inline-block;
    font-size: 0.68rem;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    padding: 3px 8px;
    border-radius: 4px;
    border: 1px solid;
    white-space: nowrap;
  }
  .pill-pending { color: var(--muted); border-color: var(--muted); }
  .pill-yes { color: var(--accent3); border-color: var(--accent3); background: rgba(126,201,138,0.08); }
  .pill-no { color: var(--red); border-color: var(--red); background: rgba(217,107,107,0.08); }
  .pill-maybe { color: var(--accent); border-color: var(--accent); background: rgba(212,168,71,0.08); }
  .icon-btn {
    background: none;
    border: none;
    color: var(--muted);
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 0.9rem;
    transition: color 0.15s, background 0.15s;
    font-family: inherit;
  }
  .icon-btn:hover { color: var(--red); background: rgba(217,107,107,0.1); }
  .add-guest-btn {
    background: var(--surface2);
    border: 1px dashed rgba(212,168,71,0.3);
    color: var(--accent);
    border-radius: var(--radius);
    padding: 10px 20px;
    font-size: 0.83rem;
    cursor: pointer;
    margin-top: 14px;
    font-family: inherit;
    letter-spacing: 0.05em;
    transition: background 0.15s, border-color 0.15s;
    display: block;
    width: 100%;
    text-align: center;
  }
  .add-guest-btn:hover { background: var(--surface3); border-color: rgba(212,168,71,0.6); }

  /* DIETARY SUMMARY */
  .diet-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 12px; }
  .diet-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 14px 16px;
    display: flex;
    align-items: center;
    gap: 12px;
  }
  .diet-icon { font-size: 1.4rem; flex-shrink: 0; }
  .diet-count { font-size: 1.4rem; font-weight: 700; color: var(--accent); line-height: 1; }
  .diet-name { font-size: 0.77rem; color: var(--muted); }

  /* SCRIPT PANEL */
  .script-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    margin-bottom: 20px;
    overflow: hidden;
  }
  .script-head {
    padding: 16px 24px;
    background: var(--surface2);
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
  }
  .script-head h3 { font-size: 0.9rem; font-weight: 600; }
  .script-head .when { font-size: 0.75rem; color: var(--accent); font-family: 'Courier New', monospace; }
  .script-body { padding: 22px 24px; }
  .script-text {
    font-size: 0.88rem;
    line-height: 1.8;
    color: var(--text);
    border-left: 2px solid var(--border);
    padding-left: 16px;
    font-style: italic;
  }
  .fill-in {
    background: rgba(212,168,71,0.15);
    color: var(--accent);
    padding: 1px 6px;
    border-radius: 3px;
    font-style: normal;
    font-family: 'Courier New', monospace;
    font-size: 0.83em;
  }
  .script-note { font-size: 0.79rem; color: var(--muted); margin-top: 14px; border-top: 1px solid var(--border2); padding-top: 12px; }
  .copy-btn {
    background: var(--surface3);
    border: 1px solid var(--border);
    color: var(--text);
    border-radius: 6px;
    padding: 6px 14px;
    font-size: 0.75rem;
    cursor: pointer;
    font-family: inherit;
    letter-spacing: 0.05em;
    transition: background 0.15s;
  }
  .copy-btn:hover { background: rgba(212,168,71,0.1); border-color: rgba(212,168,71,0.3); }
  .copy-btn.copied { color: var(--accent3); border-color: var(--accent3); }

  /* TRANSIT PANEL */
  .transit-directions { display: grid; gap: 16px; }
  .direction-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 18px 22px;
  }
  .direction-from {
    font-size: 0.82rem;
    color: var(--muted);
    margin-bottom: 8px;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    font-size: 0.68rem;
  }
  .direction-steps { font-size: 0.88rem; line-height: 1.7; }
  .direction-steps strong { color: var(--accent2); }

  /* SHARE TEXT */
  .share-block {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 24px;
  }
  .share-text {
    font-size: 0.9rem;
    line-height: 1.8;
    color: var(--text);
    white-space: pre-wrap;
    font-family: 'Courier New', monospace;
  }

  /* GENERAL BUTTON */
  .btn {
    display: inline-block;
    background: var(--accent);
    color: #0d0f18;
    border: none;
    border-radius: 7px;
    padding: 9px 22px;
    font-size: 0.83rem;
    font-weight: 600;
    cursor: pointer;
    font-family: inherit;
    letter-spacing: 0.04em;
    transition: opacity 0.15s;
  }
  .btn:hover { opacity: 0.88; }
  .btn-ghost {
    background: transparent;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 7px;
    padding: 8px 20px;
    font-size: 0.83rem;
    cursor: pointer;
    font-family: inherit;
    transition: border-color 0.15s, background 0.15s;
  }
  .btn-ghost:hover { border-color: rgba(212,168,71,0.4); background: rgba(212,168,71,0.05); }

  @media (max-width: 620px) {
    header { padding: 28px 18px 24px; }
    header h1 { font-size: 1.5rem; }
    nav { padding: 0 16px; }
    .progress-strip { grid-template-columns: 1fr; }
    .main { padding: 20px 14px 0; }
  }
</style>
</head>
<body>

<nav>
  <div class="nav-brand">Mar 27 Dinner</div>
  <div class="nav-tabs">
    <button class="tab-btn active" onclick="switchTab('overview')">Overview</button>
    <button class="tab-btn" onclick="switchTab('guests')">Guests</button>
    <button class="tab-btn" onclick="switchTab('venue')">Venue</button>
    <button class="tab-btn" onclick="switchTab('scripts')">Call Scripts</button>
    <button class="tab-btn" onclick="switchTab('transit')">Transit</button>
    <button class="tab-btn" onclick="switchTab('share')">Share</button>
  </div>
</nav>

<header>
  <div class="header-top">
    <div>
      <div class="event-label">Group Dinner Organizer</div>
      <h1>Vancouver Dinner</h1>
      <div class="sub">Friday, March 27, 2026 &middot; 5&ndash;10 people &middot; Greater Vancouver Area</div>
    </div>
    <div class="countdown-block">
      <span id="countdown-days">14</span>
      <div class="countdown-label">days remaining</div>
    </div>
  </div>
</header>

<!-- PROGRESS STRIP -->
<div class="progress-strip">
  <div class="prog-step active-step" id="step-1">
    <div class="prog-date">Mar 13 &mdash; Today</div>
    <div class="prog-label">
      <span class="prog-check" id="chk-1" onclick="toggleCheck(1)"></span>
      Call restaurant
    </div>
  </div>
  <div class="prog-step" id="step-2">
    <div class="prog-date">Mar 14 &mdash; Sat</div>
    <div class="prog-label">
      <span class="prog-check" id="chk-2" onclick="toggleCheck(2)"></span>
      Confirm headcount
    </div>
  </div>
  <div class="prog-step" id="step-3">
    <div class="prog-date">Mar 20 &mdash; Fri</div>
    <div class="prog-label">
      <span class="prog-check" id="chk-3" onclick="toggleCheck(3)"></span>
      Collect dietary info
    </div>
  </div>
  <div class="prog-step" id="step-4">
    <div class="prog-date">Mar 25 &mdash; Wed</div>
    <div class="prog-label">
      <span class="prog-check" id="chk-4" onclick="toggleCheck(4)"></span>
      Confirm reservation
    </div>
  </div>
  <div class="prog-step" id="step-5">
    <div class="prog-date">Mar 27 &mdash; Fri</div>
    <div class="prog-label">
      <span class="prog-check" id="chk-5" onclick="toggleCheck(5)"></span>
      Dinner night
    </div>
  </div>
</div>

<div class="main">

  <!-- OVERVIEW TAB -->
  <div class="tab-panel active" id="panel-overview">
    <section>
      <div class="section-label">Status at a Glance</div>
      <div class="status-grid">
        <div class="stat-card">
          <div class="stat-num" id="stat-confirmed">0</div>
          <div class="stat-label">Guests confirmed</div>
        </div>
        <div class="stat-card">
          <div class="stat-num" id="stat-pending">0</div>
          <div class="stat-label">Awaiting reply</div>
        </div>
        <div class="stat-card">
          <div class="stat-num" id="stat-dietary">0</div>
          <div class="stat-label">Dietary restrictions flagged</div>
        </div>
        <div class="stat-card">
          <div class="stat-num" id="stat-venue">--</div>
          <div class="stat-label">Venue selected</div>
        </div>
      </div>
    </section>

    <section>
      <div class="section-label">Immediate Actions</div>
      <div style="display:grid; gap:12px;">
        <div style="background:var(--surface); border:1px solid rgba(217,107,107,0.3); border-left:3px solid var(--red); border-radius:var(--radius); padding:16px 20px;">
          <div style="font-size:0.7rem; letter-spacing:0.12em; text-transform:uppercase; color:var(--red); margin-bottom:4px;">Urgent &mdash; Today</div>
          <div style="font-size:0.9rem; margin-bottom:4px;">Call your chosen restaurant and make the reservation.</div>
          <div style="font-size:0.8rem; color:var(--muted);">Friday March 27 fills up. Most downtown restaurants will be at capacity by Tuesday next week. Call today, not tomorrow.</div>
        </div>
        <div style="background:var(--surface); border:1px solid rgba(212,168,71,0.2); border-left:3px solid var(--accent); border-radius:var(--radius); padding:16px 20px;">
          <div style="font-size:0.7rem; letter-spacing:0.12em; text-transform:uppercase; color:var(--accent); margin-bottom:4px;">This Week</div>
          <div style="font-size:0.9rem; margin-bottom:4px;">Add all guests to the Guests tab and send the invite message.</div>
          <div style="font-size:0.8rem; color:var(--muted);">Use the Share tab to generate a ready-to-send message with venue, time, and transit details.</div>
        </div>
        <div style="background:var(--surface); border:1px solid rgba(95,168,199,0.2); border-left:3px solid var(--accent2); border-radius:var(--radius); padding:16px 20px;">
          <div style="font-size:0.7rem; letter-spacing:0.12em; text-transform:uppercase; color:var(--accent2); margin-bottom:4px;">By Mar 20</div>
          <div style="font-size:0.9rem; margin-bottom:4px;">Collect dietary restrictions from every confirmed guest.</div>
          <div style="font-size:0.8rem; color:var(--muted);">Severe allergies (nuts, shellfish) must be communicated to the restaurant atbooking and again on your March 25 confirmation call.</div>
        </div>
      </div>
    </section>

    <section>
      <div class="section-label">Dietary Summary</div>
      <div class="diet-grid" id="diet-summary">
        <div class="diet-card"><div class="diet-icon">V</div><div><div class="diet-count" id="dc-veg">0</div><div class="diet-name">Vegetarian</div></div></div>
        <div class="diet-card"><div class="diet-icon">GF</div><div><div class="diet-count" id="dc-gf">0</div><div class="diet-name">Gluten-Free</div></div></div>
        <div class="diet-card"><div class="diet-icon">VN</div><div><div class="diet-count" id="dc-vegan">0</div><div class="diet-name">Vegan</div></div></div>
        <div class="diet-card"><div class="diet-icon">HA</div><div><div class="diet-count" id="dc-halal">0</div><div class="diet-name">Halal</div></div></div>
        <div class="diet-card"><div class="diet-icon">AL</div><div><div class="diet-count" id="dc-allergy">0</div><div class="diet-name">Severe Allergy</div></div></div>
        <div class="diet-card"><div class="diet-icon">DF</div><div><div class="diet-count" id="dc-dairy">0</div><div class="diet-name">Dairy-Free</div></div></div>
      </div>
    </section>
  </div>

  <!-- GUESTS TAB -->
  <div class="tab-panel" id="panel-guests">
    <section>
      <div class="section-label">Guest List</div>
      <div class="guest-table-wrap">
        <table class="guest-table" id="guest-table">
          <thead>
            <tr>
              <th>#</th>
              <th>Name</th>
              <th>Area / Neighbourhood</th>
              <th>Phone / Contact</th>
              <th>RSVP Status</th>
              <th>Dietary Restrictions</th>
              <th></th>
            </tr>
          </thead>
          <tbody id="guest-tbody">
          </tbody>
        </table>
      </div>
      <button class="add-guest-btn" onclick="addGuest()">+ Add Guest</button>
    </section>
  </div>

  <!-- VENUE TAB -->
  <div class="tab-panel" id="panel-venue">
    <section>
      <div class="section-label">Select Your Venue</div>
      <p style="font-size:0.87rem; color:var(--muted); margin-bottom:18px;">Click a venue to mark it as your choice. This will update scripts and the share message with the correct address and transit directions.</p>
