let state = {
  checks: {},
  guests: [],
  venue: null
};

function loadState() {
  try {
    const s = localStorage.getItem(STATE_KEY);
    if (s) state = Object.assign(state, JSON.parse(s));
  } catch(e) {}
}

function saveState() {
  try { localStorage.setItem(STATE_KEY, JSON.stringify(state)); } catch(e) {}
}

// ---- VENUE DATA ----
