// ---- TABS ----
function switchTab(id) {
  document.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.getElementById('panel-' + id).classList.add('active');
  document.querySelectorAll('.tab-btn').forEach(b => {
    if (b.getAttribute('onclick') === "switchTab('" + id + "')") b.classList.add('active');
  });
}

// ---- COUNTDOWN ----
function updateCountdown() {
  const dinner = new Date('2026-03-27T19:00:00-08:00');
  const now = new Date();
  const diff = Math.ceil((dinner - now) / (1000 * 60 * 60 * 24));
  document.getElementById('countdown-days').textContent = Math.max(0, diff);
}

// ---- PROGRESS CHECKS ----
function toggleCheck(n) {
  state.checks[n] = !state.checks[n];
  renderChecks();
  saveState();
}

function renderChecks() {
  for (let i = 1; i <= 5; i++) {
    const el = document.getElementById('chk-' + i);
    const step = document.getElementById('step-' + i);
    if (state.checks[i]) {
      el.classList.add('checked');
      step.classList.add('done');
      step.classList.remove('active-step');
    } else {
      el.classList.remove('checked');
      step.classList.remove('done');
    }
  }
}

// ---- GUEST MANAGEMENT ----
const DIETARY_OPTIONS = [
  'None', 'Vegetarian', 'Vegan', 'Gluten-Free', 'Halal', 'Dairy-Free',
  'Nut Allergy (severe)', 'Shellfish Allergy', 'Other'
];
const RSVP_OPTIONS = ['Pending', 'Yes', 'No', 'Maybe'];

function addGuest(data) {
  const id = Date.now() + Math.random();
  const guest = data || { id, name: '', area: '', phone: '', rsvp: 'Pending', dietary: 'None' };
  if (!data) { guest.id = id; state.guests.push(guest); saveState(); }
  renderGuests();
  updateStats();
}

function removeGuest(id) {
  state.guests = state.guests.filter(g => g.id !== id);
  saveState();
  renderGuests();
  updateStats();
}

function updateGuest(id, field, value) {
  const g = state.guests.find(g => g.id === id);
  if (g) { g[field] = value; saveState(); updateStats(); }
}

function renderGuests() {
  const tbody = document.getElementById('guest-tbody');
  tbody.innerHTML = '';
  state.guests.forEach((g, i) => {
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td style="color:var(--muted); font-size:0.8rem;">${i + 1}</td>
